# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import json
import requests

# RabbitMQ Management HTTP API endpoint URL
url = "http://localhost:15672/api/vhosts"

# Username and password for the RabbitMQ user account
username = "guest"
password = "guest"

# Virtual host name for the application
vhost_name = "app1"

# Create a new virtual host
response = requests.post(url, json={"vhost": vhost_name}, auth=(username, password))

# Check if the virtual host was created successfully
if response.status_code == 201:
    print("Virtual host '{}' created successfully.".format(vhost_name))
else:
    print("Error creating virtual host: {}".format(response.text))

# Set up a user for the application
user = {"username": "app1user", "password": "password"}
response = requests.put("http://localhost:15672/api/users/%s" % vhost_name, json=user, auth=(username, password))

# Check if the user was created successfully
if response.status_code == 204:
    print("User '{}' created successfully.".format(user["username"]))
else:
    print("Error creating user: {}".format(response.text))

# Grant permissions for queue operations
permissions = {
    "configure": ".*",
    "write": ".*",
    "read": ".*"
}
response = requests.put("http://localhost:15672/api/permissions/%s/%s" % (vhost_name, user["username"]), json=permissions, auth=(username, password))

# Check if the permissions were granted successfully
if response.status_code == 204:
    print("Permissions granted successfully.")
else:
    print("Error granting permissions: {}".format(response.text))